// // This comment suggests that the output remains 0 until the register is reset, which is the opposite of the actual behavior.
module top_module(
	input clk,
	input reset,
	input [1:0] in,
	output reg [1:0] out);reg [1:0] d_last;

	always @(posedge clk) begin
		d_last <= in;
		if (reset)
			out <= '0;
		else
			out <= out | (in & ~d_last);
	end

endmodule
